//! WebGl2Device — WebGL2 device backend for browsers without WebGPU.
//!
//! WebGL2 has no compute shaders. Instead, computation is performed via
//! render-to-texture with fragment shaders (generated by `GlslRenderer`):
//!
//! 1. Input data is uploaded to RGBA32F/RGBA32I textures
//! 2. A full-screen quad is drawn with a fragment shader that reads inputs
//! 3. The fragment shader writes computed results to a framebuffer attachment
//! 4. Results are read back via readPixels (or async PBO where available)
//!
//! ## Architecture
//!
//! The Rust side provides:
//! - Type definitions for texture-backed buffers (`WebGl2Buffer`)
//! - Buffer layout metadata for JS FFI (`TextureLayout`)
//! - Compiled program representation (`WebGl2Program`)
//! - Trait implementations: `Allocator`, `Compiler`, `Executor`
//!
//! The actual WebGL2 context creation and GL calls happen in JavaScript.
//! The Rust side generates GLSL source and buffer layout metadata that the
//! JS runtime consumes via wasm-bindgen FFI (not implemented here — this
//! crate defines the Rust-side types and renderer only).
//!
//! ## Performance
//!
//! WebGL2 render-to-texture compute is 3-5x slower than native WebGPU
//! compute shaders due to:
//! - Fragment shader overhead (rasterization pipeline vs compute pipeline)
//! - Texture read/write latency vs storage buffer random access
//! - No shared memory / workgroup synchronization
//! - 4-component RGBA packing overhead
//! - readPixels synchronization stalls
//!
//! This is acceptable as a fallback for the ~25% of browser users
//! (especially iOS 15-25) that lack WebGPU support.
//!
//! ## Reduce Operations
//!
//! Reductions use multi-pass ping-pong texture rendering:
//! - Pass N reads texture A, reduces pairs, writes to texture B (half width)
//! - Pass N+1 reads texture B, reduces pairs, writes to texture A (quarter width)
//! - Continue until single texel remains
//! - Each pass is a separate draw call with a GlslRenderer-generated shader
//!
//! The `WebGl2Device::plan_reduce_passes` method computes the pass schedule
//! and intermediate texture dimensions.

use crate::dtype::DType;

/// Texture format used for a WebGL2 buffer.
///
/// WebGL2 supports limited texture internal formats for render targets:
/// - `RGBA32F`: 4x float32 per texel (requires `EXT_color_buffer_float`)
/// - `RGBA32I`: 4x int32 per texel
/// - `RGBA32UI`: 4x uint32 per texel
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TextureFormat {
    /// `GL_RGBA32F` — 4x float32 per texel. Used for Float32 and Bool data.
    Rgba32f,
    /// `GL_RGBA32I` — 4x int32 per texel. Used for Int32 data.
    Rgba32i,
    /// `GL_RGBA32UI` — 4x uint32 per texel. Used for UInt32 data.
    Rgba32ui,
}

impl TextureFormat {
    /// Bytes per texel (always 16: 4 components * 4 bytes each).
    pub const BYTES_PER_TEXEL: usize = 16;

    /// Components per texel (always 4 for RGBA).
    pub const COMPONENTS_PER_TEXEL: usize = 4;

    /// Select the appropriate texture format for a (narrowed) dtype.
    pub fn for_dtype(dtype: DType) -> Self {
        let narrowed = dtype.narrow_webgl2();
        match narrowed {
            DType::Float32 | DType::Bool => Self::Rgba32f,
            DType::Int32 => Self::Rgba32i,
            DType::UInt32 => Self::Rgba32ui,
            _ => unreachable!(
                "narrow_webgl2 should reduce all types to f32/i32/u32/bool, got {:?}",
                narrowed
            ),
        }
    }

    /// WebGL2 internal format constant value.
    pub fn gl_internal_format(self) -> u32 {
        match self {
            Self::Rgba32f => 0x8814,  // GL_RGBA32F
            Self::Rgba32i => 0x8D82,  // GL_RGBA32I
            Self::Rgba32ui => 0x8D70, // GL_RGBA32UI
        }
    }

    /// WebGL2 format constant for readPixels / texImage2D.
    pub fn gl_format(self) -> u32 {
        match self {
            Self::Rgba32f => 0x1908,  // GL_RGBA
            Self::Rgba32i => 0x8D99,  // GL_RGBA_INTEGER
            Self::Rgba32ui => 0x8D99, // GL_RGBA_INTEGER
        }
    }

    /// WebGL2 type constant for readPixels / texImage2D.
    pub fn gl_type(self) -> u32 {
        match self {
            Self::Rgba32f => 0x1406,  // GL_FLOAT
            Self::Rgba32i => 0x1404,  // GL_INT
            Self::Rgba32ui => 0x1405, // GL_UNSIGNED_INT
        }
    }
}

/// Layout for packing linear buffer data into a 2D texture.
///
/// Maps a 1D array of `num_elements` values into a 2D texture where
/// each RGBA texel stores 4 consecutive values. The texture width is
/// chosen to be the smallest power of 2 that fits the data (capped at
/// `MAX_TEXTURE_WIDTH`).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TextureLayout {
    /// Number of logical elements in the buffer.
    pub num_elements: usize,
    /// Texture width in texels.
    pub tex_width: usize,
    /// Texture height in texels.
    pub tex_height: usize,
    /// Texture format.
    pub format: TextureFormat,
}

impl TextureLayout {
    /// Maximum texture width (WebGL2 guarantees at least 4096).
    pub const MAX_TEXTURE_WIDTH: usize = 4096;

    /// Compute the texture layout for a buffer of `num_elements` with the given dtype.
    pub fn for_buffer(num_elements: usize, dtype: DType) -> Self {
        let format = TextureFormat::for_dtype(dtype);
        // Number of RGBA texels needed (4 elements per texel, round up)
        let num_texels = num_elements.div_ceil(TextureFormat::COMPONENTS_PER_TEXEL);

        // Choose width: smallest power of 2 >= sqrt(num_texels), capped
        let tex_width = if num_texels == 0 {
            1
        } else {
            let sqrt = (num_texels as f64).sqrt().ceil() as usize;
            sqrt.next_power_of_two().min(Self::MAX_TEXTURE_WIDTH)
        };
        let tex_height = if num_texels == 0 {
            1
        } else {
            num_texels.div_ceil(tex_width)
        };

        Self {
            num_elements,
            tex_width,
            tex_height,
            format,
        }
    }

    /// Total texture memory in bytes.
    pub fn size_bytes(&self) -> usize {
        self.tex_width * self.tex_height * TextureFormat::BYTES_PER_TEXEL
    }
}

/// A texture-backed buffer handle for WebGL2.
///
/// On the JS side, this corresponds to a WebGLTexture object plus an
/// associated WebGLFramebuffer for render-to-texture output.
/// The Rust side tracks layout metadata; the JS side owns the GL objects.
#[derive(Debug, Clone)]
pub struct WebGl2Buffer {
    /// Unique buffer ID (matches the JS-side texture/framebuffer pair).
    pub id: u32,
    /// Layout describing how data is packed into the texture.
    pub layout: TextureLayout,
    /// Element dtype (post-narrowing).
    pub dtype: DType,
}

/// A compiled WebGL2 shader program.
///
/// On the JS side, this corresponds to a linked WebGLProgram with the
/// full-screen quad vertex shader and the GlslRenderer-generated
/// fragment shader.
#[derive(Debug, Clone)]
pub struct WebGl2Program {
    /// Unique program ID (matches the JS-side WebGLProgram).
    pub id: u32,
    /// The GLSL ES 3.0 fragment shader source.
    pub fragment_source: String,
    /// The vertex shader source (full-screen quad, always the same).
    pub vertex_source: String,
    /// Entry point name (always "main" for GLSL).
    pub entry: String,
}

impl WebGl2Program {
    /// The canonical full-screen quad vertex shader for WebGL2 compute.
    ///
    /// Draws a full-screen triangle that covers the entire viewport.
    /// The fragment shader runs once per output texel.
    pub const FULLSCREEN_QUAD_VS: &'static str = concat!(
        "#version 300 es\n",
        "precision highp float;\n",
        "\n",
        "// Full-screen triangle: 3 vertices, no vertex buffer needed.\n",
        "// Vertex 0: (-1, -1), Vertex 1: (3, -1), Vertex 2: (-1, 3)\n",
        "// This single triangle covers the entire clip space [-1,1]^2.\n",
        "void main() {\n",
        "    float x = float((gl_VertexID & 1) << 2) - 1.0;\n",
        "    float y = float((gl_VertexID >> 1 & 1) << 2) - 1.0;\n",
        "    gl_Position = vec4(x, y, 0.0, 1.0);\n",
        "}\n",
    );
}

/// A single pass in a multi-pass reduction.
///
/// For reduce operations, the `WebGl2Device` orchestrates multiple
/// render-to-texture passes that progressively reduce the data.
#[derive(Debug, Clone)]
pub struct ReducePass {
    /// Input texture layout for this pass.
    pub input_layout: TextureLayout,
    /// Output texture layout for this pass.
    pub output_layout: TextureLayout,
    /// Number of elements being reduced per output element in this pass.
    pub reduce_factor: usize,
    /// Pass index (0-based).
    pub pass_index: usize,
}

/// Plan the multi-pass ping-pong reduction schedule.
///
/// Given `input_elements` to reduce to `output_elements`, returns the
/// sequence of passes needed. Each pass reduces by a factor of up to
/// `max_reduce_per_pass` (limited by max texture width to avoid
/// exceeding GLSL loop iteration limits).
///
/// Returns an empty vec if `input_elements == output_elements` (no-op).
pub fn plan_reduce_passes(
    input_elements: usize,
    output_elements: usize,
    dtype: DType,
) -> Vec<ReducePass> {
    if input_elements <= output_elements {
        return Vec::new();
    }

    let total_reduce = input_elements / output_elements;
    let mut passes = Vec::new();
    let mut remaining = total_reduce;
    let mut current_elements = input_elements;

    // Each pass reduces by up to max_reduce_per_pass elements.
    // We cap this at 4096 to keep fragment shader loops reasonable.
    let max_reduce_per_pass: usize = 4096;

    let mut pass_index = 0;
    while remaining > 1 {
        let factor = remaining.min(max_reduce_per_pass);
        let next_elements = current_elements / factor;

        passes.push(ReducePass {
            input_layout: TextureLayout::for_buffer(current_elements, dtype),
            output_layout: TextureLayout::for_buffer(next_elements, dtype),
            reduce_factor: factor,
            pass_index,
        });

        current_elements = next_elements;
        remaining /= factor;
        pass_index += 1;
    }

    passes
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_texture_format_for_dtype() {
        assert_eq!(
            TextureFormat::for_dtype(DType::Float32),
            TextureFormat::Rgba32f
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Float64),
            TextureFormat::Rgba32f
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Int32),
            TextureFormat::Rgba32i
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Int64),
            TextureFormat::Rgba32i
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::UInt32),
            TextureFormat::Rgba32ui
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::UInt64),
            TextureFormat::Rgba32ui
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Bool),
            TextureFormat::Rgba32f
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Float16),
            TextureFormat::Rgba32f
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::BFloat16),
            TextureFormat::Rgba32f
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Int8),
            TextureFormat::Rgba32i
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::Int16),
            TextureFormat::Rgba32i
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::UInt8),
            TextureFormat::Rgba32ui
        );
        assert_eq!(
            TextureFormat::for_dtype(DType::UInt16),
            TextureFormat::Rgba32ui
        );
    }

    #[test]
    fn test_texture_layout_small() {
        let layout = TextureLayout::for_buffer(16, DType::Float32);
        assert_eq!(layout.num_elements, 16);
        // 16 elements / 4 = 4 texels -> sqrt(4)=2 -> next_power_of_two(2) = 2
        assert_eq!(layout.tex_width, 2);
        assert_eq!(layout.tex_height, 2);
        assert_eq!(layout.format, TextureFormat::Rgba32f);
    }

    #[test]
    fn test_texture_layout_large() {
        let layout = TextureLayout::for_buffer(1_000_000, DType::Float32);
        assert_eq!(layout.num_elements, 1_000_000);
        // 1_000_000 / 4 = 250_000 texels
        assert!(layout.tex_width <= TextureLayout::MAX_TEXTURE_WIDTH);
        assert!(layout.tex_width * layout.tex_height >= 250_000);
    }

    #[test]
    fn test_texture_layout_zero() {
        let layout = TextureLayout::for_buffer(0, DType::Float32);
        assert_eq!(layout.tex_width, 1);
        assert_eq!(layout.tex_height, 1);
    }

    #[test]
    fn test_reduce_passes_noop() {
        let passes = plan_reduce_passes(64, 64, DType::Float32);
        assert!(passes.is_empty());
    }

    #[test]
    fn test_reduce_passes_simple() {
        let passes = plan_reduce_passes(1024, 1, DType::Float32);
        assert!(!passes.is_empty());
        // Each pass reduces, final output should have 1 element
        let last = passes.last().unwrap();
        assert_eq!(last.output_layout.num_elements, 1);
    }

    #[test]
    fn test_reduce_passes_large() {
        // Large reduction that needs multiple passes
        let passes = plan_reduce_passes(16_777_216, 1, DType::Float32);
        assert!(passes.len() >= 2, "16M->1 should need multiple passes");
        // Verify pass chain: each output feeds next input
        for i in 1..passes.len() {
            assert_eq!(
                passes[i].input_layout.num_elements,
                passes[i - 1].output_layout.num_elements
            );
        }
    }

    #[test]
    fn test_fullscreen_quad_vs() {
        let vs = WebGl2Program::FULLSCREEN_QUAD_VS;
        assert!(vs.contains("#version 300 es"));
        assert!(vs.contains("gl_VertexID"));
        assert!(vs.contains("gl_Position"));
    }
}
